SENSITIVE_FIELDS = {
    'password', 'passwd', 'pwd', 'secret', 'token', 'access_token',
    'refresh_token', 'api_key', 'apikey', 'authorization', 'auth_token',
    'session_id', 'sessionid', 'cookie', 'set-cookie', 'x-api-key',
    'credit_card', 'card_number', 'cvv', 'ssn', 'social_security',
}

SENSITIVE_HEADER_KEYS = {
    'authorization', 'cookie', 'set-cookie', 'x-api-key',
    'x-auth-token', 'proxy-authorization',
}


def redact_value(key, value):
    """Redact sensitive values while preserving structure for debugging."""
    key_lower = key.lower().replace('-', '_').replace(' ', '_')
    if key_lower in SENSITIVE_FIELDS or any(sf in key_lower for sf in SENSITIVE_FIELDS):
        if isinstance(value, str) and len(value) > 4:
            return f"***REDACTED*** (length={len(value)}, starts_with='{value[:2]}...')"
        return "***REDACTED***"
    return value


def redact_dict(data, depth=0, max_depth=10):
    """Recursively redact sensitive fields from a dictionary."""
    if depth > max_depth:
        return "***MAX_DEPTH_EXCEEDED***"

    if isinstance(data, dict):
        return {k: redact_dict(redact_value(k, v), depth + 1, max_depth)
                for k, v in data.items()}
    elif isinstance(data, list):
        return [redact_dict(item, depth + 1, max_depth) for item in data]
    return data


def redact_headers(headers):
    """Redact sensitive headers."""
    redacted = {}
    for key, value in headers:
        if key.lower() in SENSITIVE_HEADER_KEYS:
            if key.lower() == 'authorization':
                # Log the auth scheme but redact the credential
                parts = value.split(' ', 1)
                if len(parts) == 2:
                    redacted[key] = f"{parts[0]} ***REDACTED***"
                else:
                    redacted[key] = "***REDACTED***"
            else:
                redacted[key] = "***REDACTED***"
        else:
            redacted[key] = value
    return redacted


