def setup_logging(app):
    """Configure comprehensive logging with rotation and multiple outputs."""

    log_dir = os.environ.get('LOG_DIR', 'logs')
    os.makedirs(log_dir, exist_ok=True)

    # Custom formatter with structured output
    class StructuredFormatter(logging.Formatter):
        def format(self, record):
            log_data = {
                'timestamp': datetime.now(timezone.utc).isoformat(),
                'level': record.levelname,
                'logger': record.name,
                'message': record.getMessage(),
                'module': record.module,
                'function': record.funcName,
                'line': record.lineno,
            }

            # Add extra fields if present
            for attr in ['request_id', 'method', 'path', 'status_code',
                         'duration_ms', 'remote_addr', 'user_id', 'user_agent']:
                if hasattr(record, attr):
                    log_data[attr] = getattr(record, attr)

            if record.exc_info and record.exc_info[0]:
                log_data['exception'] = self.formatException(record.exc_info)

            return json.dumps(log_data)

    # Human-readable formatter for console
    console_formatter = logging.Formatter(
        '%(asctime)s [%(levelname)s] [%(name)s] '
        '[req:%(request_id)s] %(message)s',
        defaults={'request_id': 'N/A'}
    )

    # Sensitive data filter
    sensitive_filter = SensitiveDataFilter()

    # --- File Handler: All logs (rotating) ---
    file_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'app.log'),
        maxBytes=10 * 1024 * 1024,  # 10MB
        backupCount=10
    )
    file_handler.setLevel(logging.DEBUG)
    file_handler.setFormatter(StructuredFormatter())
    file_handler.addFilter(sensitive_filter)

    # --- File Handler: Errors only ---
    error_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'error.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=10
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(StructuredFormatter())
    error_handler.addFilter(sensitive_filter)

    # --- File Handler: Access log ---
    access_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'access.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=10
    )
    access_handler.setLevel(logging.INFO)
    access_handler.setFormatter(StructuredFormatter())
    access_handler.addFilter(sensitive_filter)

    # --- Console Handler ---
    console_handler = logging.StreamHandler()
    console_handler.setLevel(logging.DEBUG if app.debug else logging.INFO)
    console_handler.setFormatter(console_formatter)
    console_handler.addFilter(sensitive_filter)

    # Configure root logger
    root_logger = logging.getLogger()
    root_logger.setLevel(logging.DEBUG)
    root_logger.addHandler(file_handler)
    root_logger.addHandler(error_handler)
    root_logger.addHandler(console_handler)

    # Configure app logger
    app_logger = logging.getLogger('app')
    app_logger.setLevel(logging.DEBUG)

    # Configure access logger
    access_logger = logging.getLogger('app.access')
    access_logger.addHandler(access_handler)

    # Configure auth logger (for login attempts - WITHOUT credentials)
    auth_logger = logging.getLogger('app.auth')
    auth_logger.setLevel(logging.INFO)

    return app_logger


