@app.before_request
def before_request_logging():
    """Log all incoming requests with redacted sensitive data."""
    g.request_id = str(uuid.uuid4())[:12]
    g.request_start_time = time.time()

    # Get request body (safely)
    request_body = None
    content_type = request.content_type or ''

    if request.is_json:
        try:
            request_body = redact_dict(request.get_json(silent=True) or {})
        except Exception:
            request_body = "***UNPARSEABLE_JSON***"
    elif 'form' in content_type:
        request_body = redact_dict(dict(request.form))
    elif request.data:
        # Don't log binary data
        if 'multipart' in content_type or 'octet-stream' in content_type:
            request_body = f"***BINARY_DATA*** (size={len(request.data)} bytes)"
        else:
            body_str = request.data.decode('utf-8', errors='replace')[:2000]
            request_body = body_str

    # Redact sensitive query parameters
    query_params = redact_dict(dict(request.args)) if request.args else None

    log_extra = {
        'request_id': g.request_id,
        'method': request.method,
        'path': request.path,
        'remote_addr': request.remote_addr,
        'user_agent': request.headers.get('User-Agent', 'Unknown'),
    }

    access_logger.info(
        "Incoming request: %s %s | IP: %s | Headers: %s | Query: %s | Body: %s",
        request.method,
        request.full_path if request.query_string else request.path,
        request.remote_addr,
        json.dumps(redact_headers(list(request.headers))),
        json.dumps(query_params) if query_params else "None",
        json.dumps(request_body) if request_body else "None",
        extra=log_extra
    )


@app.after_request
def after_request_logging(response):
    """Log all outgoing responses."""
    duration = (time.time() - g.get('request_start_time', time.time())) * 1000

    # Log response body for non-binary, non-large responses
    response_body = None
    content_type = response.content_type or ''
    if ('json' in content_type or 'text' in content_type):
        try:
            resp_data = response.get_data(as_text=True)
            if len(resp_data) <= 5000:
                if 'json' in content_type:
                    response_body = redact_dict(json.loads(resp_data))
                else:
                    response_body = resp_data[:2000]
            else:
                response_body = f"***LARGE_RESPONSE*** (size={len(resp_data)} bytes)"
        except Exception:
            response_body = "***UNPARSEABLE***"

    log_extra = {
        'request_id': g.get('request_id', 'unknown'),
        'method': request.method,
        'path': request.path,
        'status_code': response.status_code,
        'duration_ms': round(duration, 2),
        'remote_addr': request.remote_addr,
        'user_agent': request.headers.get('User-Agent', 'Unknown'),
    }

    log_level = logging.INFO
    if response.status_code >= 500:
        log_level = logging.ERROR
    elif response.status_code >= 400:
        log_level = logging.WARNING

    access_logger.log(
        log_level,
        "Response: %s %s -> %d | Duration: %.2fms | Body: %s",
        request.method,
        request.path,
        response.status_code,
        duration,
        json.dumps(response_body) if response_body else "None",
        extra=log_extra
    )

    # Add request ID to response headers for tracing
    response.headers['X-Request-ID'] = g.get('request_id', 'unknown')
    return response


