import hashlib

USERS_DB = {
    'admin': {
        'password_hash': hashlib.sha256('admin123'.encode()).hexdigest(),
        'user_id': 1,
        'role': 'admin',
        'email': 'admin@example.com'
    },
    'user1': {
        'password_hash': hashlib.sha256('password1'.encode()).hexdigest(),
        'user_id': 2,
        'role': 'user',
        'email': 'user1@example.com'
    }
}

ACTIVE_TOKENS = {}


def generate_token(user_id):
    token = str(uuid.uuid4())
    ACTIVE_TOKENS[token] = user_id
    return token


def require_auth(f):
    """Authentication decorator that logs auth attempts safely."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        log_extra = {
            'request_id': g.get('request_id', 'unknown'),
            'method': request.method,
            'path': request.path,
            'remote_addr': request.remote_addr,
            'user_agent': request.headers.get('User-Agent', 'Unknown'),
        }

        if not auth_header.startswith('Bearer '):
            auth_logger.warning(
                "Authentication failed: Missing or invalid Authorization header "
                "| IP: %s | Path: %s",
                request.remote_addr,
                request.path,
                extra=log_extra
            )
            return jsonify({'error': 'Authorization header required'}), 401

        token = auth_header.split(' ', 1)[1]

        # SECURITY: Log token fingerprint, NOT the full token
        token_fingerprint = f"{token[:4]}...{token[-4:]}" if len(token) > 8 else "***"

        if token not in ACTIVE_TOKENS:
            auth_logger.warning(
                "Authentication failed: Invalid token (fingerprint: %s) "
                "| IP: %s | Path: %s",
                token_fingerprint,
                request.remote_addr,
                request.path,
                extra=log_extra
            )
            return jsonify({'error': 'Invalid or expired token'}), 401

        g.user_id = ACTIVE_TOKENS[token]
        auth_logger.info(
            "Authentication successful: user_id=%s | token_fingerprint=%s | Path: %s",
            g.user_id,
            token_fingerprint,
            request.path,
            extra=log_extra
        )

        return f(*args, **kwargs)
    return decorated


