@app.route('/api/login', methods=['POST'])
def login():
    """
    Login endpoint - logs authentication attempts WITHOUT credentials.

    SECURITY NOTE: We log the username and whether the attempt succeeded
    or failed, but NEVER log the password or generated token in full.
    """
    data = request.get_json(silent=True) or {}
    username = data.get('username', '')
    password = data.get('password', '')

    log_extra = {
        'request_id': g.get('request_id', 'unknown'),
        'method': request.method,
        'path': request.path,
        'remote_addr': request.remote_addr,
        'user_agent': request.headers.get('User-Agent', 'Unknown'),
    }

    if not username or not password:
        auth_logger.warning(
            "Login failed: Missing credentials | IP: %s | Username provided: %s",
            request.remote_addr,
            bool(username),
            extra=log_extra
        )
        return jsonify({'error': 'Username and password are required'}), 400

    user = USERS_DB.get(username)
    password_hash = hashlib.sha256(password.encode()).hexdigest()

    if not user or user['password_hash'] != password_hash:
        # SECURITY: Log the attempt but NOT the password
        auth_logger.warning(
            "Login failed: Invalid credentials | Username: '%s' | IP: %s | "
            "User exists: %s | Attempt time: %s",
            username,
            request.remote_addr,
            username in USERS_DB,
            datetime.now(timezone.utc).isoformat(),
            extra=log_extra
        )
        return jsonify({'error': 'Invalid username or password'}), 401

    token = generate_token(user['user_id'])
    # SECURITY: Only log a fingerprint of the token
    token_fingerprint = f"{token[:4]}...{token[-4:]}"

    auth_logger.info(
        "Login successful | Username: '%s' | User ID: %s | Role: %s | "
        "IP: %s | Token fingerprint: %s",
        username,
        user['user_id'],
        user['role'],
        request.remote_addr,
        token_fingerprint,
        extra=log_extra
    )

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user': {
            'user_id': user['user_id'],
            'username': username,
            'role': user['role'],
            'email': user['email']
        }
    })


